CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_recv_msg() RETURNS trigger AS $BODY$
BEGIN
  /*ห้าม Gen item_no ,seq_no*/

  if coalesce(NEW.trans_timefrac::text, '') = '' then NEW.trans_timefrac :=0;end if;
  if coalesce(NEW.trans_amount::text, '') = '' then NEW.trans_amount :=0;end if;
  if coalesce(NEW.trans_fee::text, '') = '' then NEW.trans_fee :=0;end if;
  if coalesce(NEW.overdraft_available::text, '') = '' then NEW.overdraft_available :=0;end if;
  if coalesce(NEW.ref_seqno::text, '') = '' then NEW.ref_seqno :=0;end if;
  if coalesce(NEW.approve_amount::text, '') = '' then NEW.approve_amount :=0;end if;

  if coalesce(NEW.response_code::text, '') = '' or NEW.response_code = ' ' then NEW.response_code :='????';end if;
  if coalesce(NEW.ref_contract::text, '') = '' or NEW.ref_contract = ' ' then NEW.ref_contract :='<>';end if;
  if coalesce(NEW.diff_retport_status::text, '') = '' or NEW.diff_retport_status = ' ' then NEW.diff_retport_status :='2';end if;

   --if :new.response_text is null or :new.response_text = ' ' then
  if NEW.response_code = '????' or NEW.response_code = '0000' then
    null;
  else
    NEW.response_text := pka_com_login.fp_dberror_text;
  end if;

  --Niorn 2023-07-10 JUN ปรับขนาด bank_code
  if trim(both NEW.bank_code) = '06'  then NEW.bank_code := '006';end if;
  if trim(both NEW.bank_code) = '25' then NEW.bank_code := '025';end if;

RETURN NEW;
end
